120â†’internal class AlternativesParsingFormatStructure<in T>(
121â†’    val mainFormat: FormatStructure<T>,
122â†’    val formats: List<FormatStructure<T>>,
123â†’) : NonConcatenatedFormatStructure<T> {
124â†’    override fun toString(): String = "AlternativesParsing($formats)"
125â†’
126â†’    override fun equals(other: Any?): Boolean =
127â†’        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
128â†’
129â†’    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
130â†’
131â†’    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
132â†’        add(mainFormat.parser())
133â†’        for (format in formats) {
134â†’            add(format.parser())
135â†’        }
136â†’    })
137â†’
138â†’    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
139â†’}
