141â†’internal class OptionalFormatStructure<in T>(
142â†’    val onZero: String,
143â†’    val format: FormatStructure<T>,
144â†’) : NonConcatenatedFormatStructure<T> {
145â†’    override fun toString(): String = "Optional($onZero, $format)"
146â†’
147â†’    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148â†’        PropertyWithDefault.fromField(field)
149â†’    }
150â†’
151â†’    override fun equals(other: Any?): Boolean =
152â†’        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153â†’
154â†’    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155â†’
156â†’    override fun parser(): ParserStructure<T> = ParserStructure(
157â†’        operations = emptyList(),
158â†’        followedBy = listOf(
159â†’            format.parser(),
160â†’            listOf(
161â†’                ConstantFormatStructure<T>(onZero).parser(),
162â†’                ParserStructure(
163â†’                    listOf(
164â†’                        UnconditionalModification {
165â†’                            for (field in fields) {
166â†’                                field.assignDefault(it)
167â†’                            }
168â†’                        }
169â†’                    ),
170â†’                    emptyList()
171â†’                )
172â†’            ).concat()
173â†’        )
174â†’    )
175â†’
176â†’    override fun formatter(): FormatterStructure<T> {
177â†’        val formatter = format.formatter()
178â†’        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179â†’        return ConditionalFormatter(
180â†’            listOf(
181â†’                predicate::test to ConstantStringFormatterStructure(onZero),
182â†’                Truth::test to formatter
183â†’            )
184â†’        )
185â†’    }
186â†’
187â†’    private class PropertyWithDefault<in T, E> private constructor(
188â†’        private val accessor: Accessor<T, E>,
189â†’        private val defaultValue: E
190â†’    ) {
191â†’        companion object {
192â†’            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
193â†’                val default = field.defaultValue
194â†’                require(default != null) {
195â†’                    "The field '${field.name}' does not define a default value"
196â†’                }
197â†’                return PropertyWithDefault(field.accessor, default)
198â†’            }
199â†’        }
200â†’
201â†’        inline fun assignDefault(target: T) {
202â†’            accessor.trySetWithoutReassigning(target, defaultValue)
203â†’        }
204â†’
205â†’        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
206â†’    }
207â†’}
208â†’
209â†’internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
210â†’
211â†’internal open class ConcatenatedFormatStructure<in T>(
212â†’    val formats: List<NonConcatenatedFormatStructure<T>>
213â†’) : FormatStructure<T> {
214â†’    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
215â†’
216â†’    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
217â†’
218â†’    override fun hashCode(): Int = formats.hashCode()
219â†’
220â†’    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
221â†’
222â†’    override fun formatter(): FormatterStructure<T> {
223â†’        val formatters = formats.map { it.formatter() }
224â†’        return if (formatters.size == 1) {
225â†’            formatters.single()
226â†’        } else {
227â†’            ConcatenatedFormatter(formatters)
228â†’        }
229â†’    }
230â†’}
231â†’
232â†’internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
233â†’    ConcatenatedFormatStructure<T>(formats) {
234â†’    private val cachedFormatter: FormatterStructure<T> by lazy { super.formatter() }
235â†’    private val cachedParser: ParserStructure<T> by lazy { super.parser() }
236â†’
237â†’    override fun formatter(): FormatterStructure<T> = cachedFormatter
238â†’
239â†’    override fun parser(): ParserStructure<T> = cachedParser
240â†’}
241â†’
242â†’private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
243â†’    fun rec(format: FormatStructure<T>) {
244â†’        when (format) {
245â†’            is BasicFormatStructure -> add(format.directive)
246â†’            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
247â†’            is ConstantFormatStructure -> {}
248â†’            is SignedFormatStructure -> rec(format.format)
249â†’            is AlternativesParsingFormatStructure -> {
250â†’                rec(format.mainFormat); format.formats.forEach { rec(it) }
251â†’            }
252â†’
253â†’            is OptionalFormatStructure -> rec(format.format)
254â†’        }
255â†’    }
256â†’    rec(format)
257â†’}
