 13â†’internal interface UtcOffsetFieldContainer {
 14â†’    var isNegative: Boolean?
 15â†’    var totalHoursAbs: Int?
 16â†’    var minutesOfHour: Int?
 17â†’    var secondsOfMinute: Int?
 18â†’}
 19â†’
 20â†’internal interface AbstractWithOffsetBuilder : DateTimeFormatBuilder.WithUtcOffset {
 21â†’    fun addFormatStructureForOffset(structure: FormatStructure<UtcOffsetFieldContainer>)
 22â†’
 23â†’    override fun offsetHours(padding: Padding) =
 24â†’        addFormatStructureForOffset(
 25â†’            SignedFormatStructure(
 26â†’                BasicFormatStructure(UtcOffsetWholeHoursDirective(padding)),
 27â†’                withPlusSign = true
 28â†’            )
 29â†’        )
 30â†’
 31â†’    override fun offsetMinutesOfHour(padding: Padding) =
 32â†’        addFormatStructureForOffset(BasicFormatStructure(UtcOffsetMinuteOfHourDirective(padding)))
 33â†’
 34â†’    override fun offsetSecondsOfMinute(padding: Padding) =
 35â†’        addFormatStructureForOffset(BasicFormatStructure(UtcOffsetSecondOfMinuteDirective(padding)))
 36â†’
 37â†’    @Suppress("NO_ELSE_IN_WHEN")
 38â†’    override fun offset(format: DateTimeFormat<UtcOffset>) = when (format) {
 39â†’        is UtcOffsetFormat -> addFormatStructureForOffset(format.actualFormat)
 40â†’    }
 41â†’}
