 43â†’internal class UtcOffsetFormat(override val actualFormat: CachedFormatStructure<UtcOffsetFieldContainer>) :
 44â†’    AbstractDateTimeFormat<UtcOffset, IncompleteUtcOffset>() {
 45â†’    companion object {
 46â†’        fun build(block: DateTimeFormatBuilder.WithUtcOffset.() -> Unit): UtcOffsetFormat {
 47â†’            val builder = Builder(AppendableFormatStructure())
 48â†’            builder.block()
 49â†’            return UtcOffsetFormat(builder.build())
 50â†’        }
 51â†’    }
 52â†’
 53â†’    private class Builder(override val actualBuilder: AppendableFormatStructure<UtcOffsetFieldContainer>) :
 54â†’        AbstractDateTimeFormatBuilder<UtcOffsetFieldContainer, Builder>, AbstractWithOffsetBuilder {
 55â†’
 56â†’        override fun addFormatStructureForOffset(structure: FormatStructure<UtcOffsetFieldContainer>) {
 57â†’            actualBuilder.add(structure)
 58â†’        }
 59â†’
 60â†’        override fun createEmpty(): Builder = Builder(AppendableFormatStructure())
 61â†’    }
 62â†’
 63â†’    override fun intermediateFromValue(value: UtcOffset): IncompleteUtcOffset =
 64â†’        IncompleteUtcOffset().apply { populateFrom(value) }
 65â†’
 66â†’    override fun valueFromIntermediate(intermediate: IncompleteUtcOffset): UtcOffset = intermediate.toUtcOffset()
 67â†’
 68â†’    override val emptyIntermediate: IncompleteUtcOffset get() = emptyIncompleteUtcOffset
 69â†’
 70â†’}
